mapper.select:
select distinct u.user_id as userId, u.user_name as userName, u.nick_name as nickName from sys_user u inner join sys_user_role ur on ur.user_id = u.user_id inner join sys_role r on r.role_id = ur.role_id where u.del_flag = '0' and u.status = '0' and r.del_flag = '0' and r.status = '0' and r.role_key = #{roleKey}
and (u.user_name like concat('%', #{userName}, '%') or u.nick_name like concat('%', #{userName}, '%'))
order by u.user_id asc
